const otpRes = await pm.sendRequest({
    method: 'POST',
    url: pm.variables.replaceIn('{{baseUrl}}/api/auth/buyer/request-otp'),
    header: {'Content-Type': 'application/json'},
    body: {mode: 'raw', raw: JSON.stringify({phoneNumber: '081111111111'})}
});
const otpJson = otpRes.json();
const otp = otpJson.data?.otp || '00000';

await sleep(500);

// Step 2: Verify OTP
const verifyRes = await pm.sendRequest({
    method: 'POST',
    url: pm.variables.replaceIn('{{baseUrl}}/api/auth/buyer/verify-otp'),
    header: {'Content-Type': 'application/json'},
    body: {mode: 'raw', raw: JSON.stringify({phoneNumber: '081111111111', otp: otp})}
});
const verifyJson = verifyRes.json();

if (verifyJson.data && verifyJson.data.token) {
    pm.collectionVariables.set('buyerToken', verifyJson.data.token);
    const decoded = verifyJson.data.token.split('.')[1];
    const payload = JSON.parse(atob(decoded));
    pm.collectionVariables.set('buyerId', String(payload.id));
    console.log('✓ buyerToken saved (buyer id=' + payload.id + ')');
}

